 17→var configuredModels = signal([]);
 18→var providerMetaSig = signal(new Map());
 19→var loading = signal(false);
 20→var detectingModels = signal(false);
 21→var detectSummary = signal(null);
 22→var detectError = signal("");
 23→var detectProgress = signal(null);
 24→var deletingProvider = signal("");
 25→var providerActionError = signal("");
 26→
 27→function countUniqueProviders(models) {
 28→	return new Set(models.map((m) => m.provider)).size;
 29→}
 30→
 31→function progressFromPayload(payload) {
 32→	return {
 33→		total: payload?.total || 0,
 34→		checked: payload?.checked || 0,
 35→		supported: payload?.supported || 0,
 36→		unsupported: payload?.unsupported || 0,
 37→		errors: payload?.errors || 0,
 38→	};
 39→}
 40→
 41→function handleModelsUpdatedEvent(payload) {
 42→	if (!payload?.phase) return;
 43→	if (payload.phase === "start") {
 44→		detectingModels.value = true;
 45→		detectError.value = "";
 46→		detectSummary.value = null;
 47→		detectProgress.value = progressFromPayload(payload);
 48→		return;
 49→	}
 50→	if (payload.phase === "progress") {
 51→		detectingModels.value = true;
 52→		detectProgress.value = progressFromPayload(payload);
 53→		return;
 54→	}
 55→	if (payload.phase === "complete") {
 56→		detectingModels.value = false;
 57→		if (payload.summary) {
 58→			detectSummary.value = payload.summary;
 59→			detectProgress.value = progressFromPayload(payload.summary);
 60→		}
 61→		return;
 62→	}
 63→	if (payload.phase === "error") {
 64→		detectingModels.value = false;
 65→		detectError.value = payload.error || t("providers:modelDetectionFailed");
 66→	}
 67→}
 68→
 69→function fetchProviders() {
 70→	loading.value = true;
 71→	return Promise.all([sendRpc("models.list_all", {}), sendRpc("providers.available", {})])
 72→		.then(([modelsRes, providersRes]) => {
 73→			loading.value = false;
 74→			var providerMeta = new Map();
 75→			var configuredProviders = [];
 76→			if (providersRes?.ok) {
 77→				configuredProviders = (providersRes.payload || []).filter(
 78→					(configuredProvider) => configuredProvider.configured,
 79→				);
 80→				for (var providerMetaEntry of providersRes.payload || []) {
 81→					providerMeta.set(providerMetaEntry.name, providerMetaEntry);
 82→				}
 83→			}
 84→			providerMetaSig.value = providerMeta;
 85→
 86→			var models = [];
 87→			if (modelsRes?.ok) {
 88→				models = (modelsRes.payload || []).map((m) => ({
 89→					...m,
 90→					providerDisplayName: providerMeta.get(m.provider)?.displayName || m.provider,
 91→					authType: providerMeta.get(m.provider)?.authType || "api-key",
 92→				}));
 93→			}
 94→
 95→			// Include configured providers that don't currently expose a model.
 96→			var modelProviders = new Set(models.map((m) => m.provider));
 97→			var providerOnlyRows = [];
 98→			providerOnlyRows = configuredProviders
 99→				.filter((providerWithoutModels) => !modelProviders.has(providerWithoutModels.name))
100→				.map((providerWithoutModels) => ({
101→					id: `provider:${providerWithoutModels.name}`,
102→					provider: providerWithoutModels.name,
103→					displayName: providerWithoutModels.displayName,
104→					providerDisplayName: providerWithoutModels.displayName,
105→					providerOnly: true,
106→					authType: providerWithoutModels.authType,
107→				}));
108→
109→			configuredModels.value = [...models, ...providerOnlyRows];
110→			updateNavCount("providers", countUniqueProviders(configuredModels.value));
111→		})
112→		.catch(() => {
113→			loading.value = false;
114→		});
115→}
116→
117→async function runDetectAllModels() {
118→	if (!connected.value || detectingModels.value) return;
119→	detectingModels.value = true;
120→	detectSummary.value = null;
121→	detectError.value = "";
122→	detectProgress.value = null;
123→
124→	try {
125→		// Phase 1: show current full list first before probing.
126→		await Promise.all([fetchModels(), fetchProviders()]);
127→		await new Promise((resolve) => {
128→			requestAnimationFrame(resolve);
129→		});
130→
131→		var res = await sendRpc("models.detect_supported", {});
132→		if (!res?.ok) {
133→			detectError.value = res?.error?.message || t("providers:failedToDetectModels");
134→			detectingModels.value = false;
135→			return;
136→		}
137→		if (res.payload?.skipped) {
138→			detectingModels.value = false;
139→			return;
140→		}
141→		detectSummary.value = res.payload || null;
142→		detectProgress.value = progressFromPayload(res.payload);
143→		await Promise.all([fetchModels(), fetchProviders()]);
144→		var p = detectProgress.value;
145→		if (!p || p.total === 0 || p.checked >= p.total) {
146→			detectingModels.value = false;
147→		}
148→	} catch (_err) {
149→		detectingModels.value = false;
150→	}
151→}
152→
153→function groupProviderRows(models, metaMap) {
154→	var groups = new Map();
155→	for (var row of models) {
156→		var key = row.provider;
157→		if (!groups.has(key)) {
158→			groups.set(key, {
159→				provider: key,
160→				providerDisplayName: row.providerDisplayName || row.displayName || key,
161→				authType: row.authType || "api-key",
162→				selectedModel: metaMap?.get(key)?.model || null,
163→				models: [],
164→			});
165→		}
166→		var groupEntry = groups.get(key);
167→		if (!row.providerOnly) {
168→			groupEntry.models.push(row);
169→		}
170→	}
171→
172→	var result = Array.from(groups.values());
173→	result.sort((a, b) => {
174→		var aOrder = metaMap?.get(a.provider)?.uiOrder;
175→		var bOrder = metaMap?.get(b.provider)?.uiOrder;
176→		var hasAOrder = Number.isFinite(aOrder);
177→		var hasBOrder = Number.isFinite(bOrder);
178→		if (hasAOrder && hasBOrder && aOrder !== bOrder) return aOrder - bOrder;
179→		if (hasAOrder && !hasBOrder) return -1;
180→		if (!hasAOrder && hasBOrder) return 1;
181→		return a.providerDisplayName.localeCompare(b.providerDisplayName);
182→	});
183→	for (var providerGroup of result) {
184→		providerGroup.models.sort((a, b) => {
185→			// Preferred > recommended > newest date > highest version number > alpha.
186→			var aPref = a.preferred ? 1 : 0;
187→			var bPref = b.preferred ? 1 : 0;
188→			if (aPref !== bPref) return bPref - aPref;
189→			var aRec = a.recommended ? 1 : 0;
190→			var bRec = b.recommended ? 1 : 0;
191→			if (aRec !== bRec) return bRec - aRec;
192→			var aTime = a.createdAt || 0;
193→			var bTime = b.createdAt || 0;
194→			if (aTime !== bTime) return bTime - aTime;
195→			var aVer = modelVersionScore(a.id);
196→			var bVer = modelVersionScore(b.id);
197→			if (aVer !== bVer) return bVer - aVer;
198→			return (a.displayName || a.id).localeCompare(b.displayName || b.id);
199→		});
200→	}
201→	return result;
202→}
