256→	}
257→
258→	return html`<div id=${`provider-${group.provider}`} class="max-w-form py-1">
259→		<div class="flex items-center justify-between gap-3">
260→			<div class="flex items-center gap-2 min-w-0">
261→				<h3 class="text-base font-semibold text-[var(--text-strong)] truncate">${group.providerDisplayName}</h3>
262→				<span class="provider-item-badge ${group.authType}">
263→					${group.authType === "oauth" ? t("providers:oauth") : group.authType === "local" ? t("providers:local") : t("providers:apiKey")}
264→				</span>
265→			</div>
266→			<div class="flex gap-2 shrink-0">
267→				${group.models.length > 0 ? html`<button class="provider-btn provider-btn-secondary provider-btn-sm" onClick=${onSelectModels}>${t("providers:preferredModels.button")}</button>` : null}
268→				<button
269→					class="provider-btn provider-btn-danger provider-btn-sm"
270→					disabled=${deletingProvider.value === group.provider}
