304→						class="text-xs text-[var(--accent)] cursor-pointer bg-transparent border-none py-1 text-left hover:underline"
305→						onClick=${() => setExpanded(!expanded)}
306→					>${expanded ? t("providers:showFewerModels") : t("providers:showAllModels", { count: hiddenCount })}</button>`
307→							: null
308→					}
309→				</div>`
310→		}
311→	</div>`;
312→}
