 67→function normalizeEndpointForCompare(rawUrl) {
 68→	if (!rawUrl) return null;
 69→	var trimmed = rawUrl.trim();
 70→	if (!trimmed) return null;
 71→	try {
 72→		var parsed = new URL(trimmed);
 73→		var pathname = parsed.pathname.replace(/\/+$/, "");
 74→		return `${parsed.protocol.toLowerCase()}//${parsed.host.toLowerCase()}${pathname}`;
 75→	} catch {
 76→		return trimmed.replace(/\/+$/, "").toLowerCase();
 77→	}
