 80→function shouldUseCustomProviderForOpenAi(provider, endpointVal) {
 81→	if (provider?.name !== "openai") return false;
 82→	var normalizedEndpoint = normalizeEndpointForCompare(endpointVal);
 83→	if (!normalizedEndpoint) return false;
 84→	var normalizedDefault = normalizeEndpointForCompare(provider.defaultBaseUrl || "https://api.openai.com/v1");
 85→	return normalizedDefault !== null && normalizedEndpoint !== normalizedDefault;
