117→function base64ToBuffer(b64) {
118→	var str = b64.replace(/-/g, "+").replace(/_/g, "/");
119→	while (str.length % 4) str += "=";
120→	var bin = atob(str);
121→	var buf = new Uint8Array(bin.length);
122→	for (var i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i);
123→	return buf.buffer;
124→}
125→
126→function bufferToBase64(buf) {
127→	var bytes = new Uint8Array(buf);
128→	var str = "";
129→	for (var b of bytes) str += String.fromCharCode(b);
130→	return btoa(str).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
131→}
