 17→/**
 18→ * Map raw error strings to user-friendly messages.
 19→ */
 20→export function humanizeProbeError(error) {
 21→	if (!error || typeof error !== "string") return error;
 22→	var lower = error.toLowerCase();
 23→
 24→	if (
 25→		lower.includes("401") ||
 26→		lower.includes("unauthorized") ||
 27→		lower.includes("invalid api key") ||
 28→		lower.includes("invalid x-api-key")
 29→	) {
 30→		return "Invalid API key. Please double-check and try again.";
 31→	}
 32→	if (lower.includes("403") || lower.includes("forbidden")) {
 33→		return "Your API key doesn't have access. Check your account permissions.";
 34→	}
 35→	if (lower.includes("permission")) {
 36→		return error;
 37→	}
 38→	if (lower.includes("429") || lower.includes("rate limit") || lower.includes("too many requests")) {
 39→		return "Rate limited by the provider. Wait a moment and try again.";
 40→	}
 41→	if (lower.includes("timeout") || lower.includes("timed out")) {
 42→		return "Connection timed out. Check your endpoint URL and try again.";
 43→	}
 44→	if (lower.includes("connection refused") || lower.includes("econnrefused")) {
 45→		return "Connection refused. Make sure the provider endpoint is running and reachable.";
 46→	}
 47→	if (lower.includes("dns") || lower.includes("getaddrinfo") || lower.includes("name or service not known")) {
 48→		return "Could not resolve the endpoint address. Check the URL and try again.";
 49→	}
 50→
 51→	return error;
 52→}
