 65→/**
 66→ * Validate provider credentials without saving them.
 67→ * Returns { valid, models?, error? }.
 68→ */
 69→export async function validateProviderKey(provider, apiKey, baseUrl, model, requestId) {
 70→	var payload = { provider, apiKey };
 71→	if (baseUrl) payload.baseUrl = baseUrl;
 72→	if (model) payload.model = model;
 73→	if (requestId) payload.requestId = requestId;
 74→
 75→	var res = await sendRpc("providers.validate_key", payload);
 76→	if (!res?.ok) {
 77→		return {
 78→			valid: false,
 79→			error: humanizeProbeError(res?.error?.serverMessage || res?.error?.message || "Failed to validate credentials."),
 80→		};
 81→	}
 82→
 83→	var data = res.payload || {};
 84→	if (data.valid) {
 85→		return { valid: true, models: data.models || [] };
 86→	}
 87→	return {
 88→		valid: false,
 89→		error: humanizeProbeError(data.error || "Validation failed."),
 90→	};
 91→}
