 93→/**
 94→ * Test a single model from the live registry.
 95→ * Returns { ok, error? }.
 96→ */
 97→export async function testModel(modelId) {
 98→	for (var attempt = 0; attempt < MODEL_TEST_RETRY_ATTEMPTS; attempt++) {
 99→		var res = await sendRpc("models.test", { modelId });
100→		if (res?.ok) {
101→			return { ok: true };
102→		}
103→
104→		var message = res?.error?.serverMessage || res?.error?.message || "Model test failed.";
105→		var lower = String(message).toLowerCase();
106→		var shouldRetry = lower.includes(MODEL_SERVICE_NOT_CONFIGURED) && attempt < MODEL_TEST_RETRY_ATTEMPTS - 1;
107→
108→		if (!shouldRetry) {
109→			return {
110→				ok: false,
111→				error: humanizeProbeError(message),
112→			};
113→		}
114→
115→		await new Promise((resolve) => {
116→			window.setTimeout(resolve, MODEL_TEST_RETRY_DELAY_MS);
117→		});
118→	}
119→
120→	return {
121→		ok: false,
122→		error: humanizeProbeError("Model test failed."),
123→	};
124→}
