145→export async function validateProviderConnection(providerName) {
146→	var res = await sendRpc("models.detect_supported", {
147→		provider: providerName,
148→		reason: "provider_credentials_validation",
149→	});
150→
151→	if (!res?.ok) {
152→		return {
153→			ok: false,
154→			message: res?.error?.message || "Failed to validate provider credentials.",
155→		};
156→	}
157→
158→	var payload = res.payload || {};
159→	var total = payload.total || 0;
160→	var supported = payload.supported || 0;
161→	var unsupported = payload.unsupported || 0;
162→	var errors = payload.errors || 0;
163→
164→	if (supported > 0) {
165→		return {
166→			ok: true,
167→			message: null,
168→		};
169→	}
170→
171→	// No probe targets usually means no model is configured yet.
172→	if (total === 0) {
173→		return {
174→			ok: true,
175→			message: null,
176→		};
177→	}
178→
179→	var reason = firstProbeFailure(payload);
180→	if (!reason) {
181→		reason = `0/${total} models responded successfully (unsupported: ${unsupported}, errors: ${errors}).`;
182→	}
183→
184→	return {
185→		ok: false,
186→		message: `Credentials were saved, but validation failed: ${reason}`,
187→	};
188→}
