function closeAll() {
	setConfiguring(null);
	setOauthProvider(null);
	setLocalProvider(null);
	setModelSelectProvider(null);
	setPhase("form");
	setProviderModels([]);
	setSelectedModels(new Set());
	setProbeResults(new Map());
	setModelSearch("");
	setSavingModels(false);
	setApiKey("");
	setEndpoint("");
