											<span class="text-sm font-medium text-[var(--text)]">${b.name}</span>
											<div class="flex flex-wrap gap-2 justify-end">
												${b.id === sysInfo.recommendedBackend && b.available ? html`<span class="recommended-badge">Recommended</span>` : null}
