    async fn shutdown_with_grace(&self, grace: std::time::Duration) -> bool {
        tokio::time::timeout(grace, self.shutdown()).await.is_ok()
    }
    /// Close all browser sessions (called on sessions.clear_all).
    async fn close_all(&self) {}
}

